        private static List<string> ParseSelectColumns(string selectParam, HashSet<string> tableColumns)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
            {
                return tableColumns.ToList();
            }

            var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries)
                .Select(c => c.Trim())
                .ToList();

            var validatedColumns = new List<string>();
            foreach (var col in requestedColumns)
            {
                string canonicalCol = tableColumns.FirstOrDefault(tc => tc.Equals(col, StringComparison.OrdinalIgnoreCase));
                if (canonicalCol == null)
                {
                    throw new ArgumentException($"Column '{SanitizeForLog(col)}' is not allowed for this table.");
                }
                validatedColumns.Add(canonicalCol);
            }

            if (validatedColumns.Count == 0)
            {
                return tableColumns.ToList();
            }

            return validatedColumns.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
        }

        private static List<FilterCondition> ParseFilters(IQueryCollection queryParams, HashSet<string> tableColumns)
        {
            var filters = new List<FilterCondition>();

            // Filter format: filter_ColumnName_operator=value
            // Example: filter_Region_eq=West&filter_Amount_gt=100
            foreach (var key in queryParams.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                if (filters.Count >= MaxFilters)
                {
                    throw new ArgumentException($"Maximum of {MaxFilters} filters allowed.");
                }

                string[] parts = key.Split('_');
                if (parts.Length != 3)
                {
                    throw new ArgumentException($"Invalid filter format: '{SanitizeForLog(key)}'. Expected format: filter_ColumnName_operator");
                }

                string columnName = parts[1];
                string operatorName = parts[2];
                string value = queryParams[key].ToString();

                // Validate column against allowlist
                string canonicalColumn = tableColumns.FirstOrDefault(tc => tc.Equals(columnName, StringComparison.OrdinalIgnoreCase));
                if (canonicalColumn == null)
                {
                    throw new ArgumentException($"Filter column '{SanitizeForLog(columnName)}' is not allowed for this table.");
                }

                // Validate operator against allowlist
                if (!AllowedOperators.Contains(operatorName))
                {
                    throw new ArgumentException($"Filter operator '{SanitizeForLog(operatorName)}' is not allowed. Allowed: {string.Join(", ", AllowedOperators)}");
                }

                // Validate value is not empty
                if (string.IsNullOrWhiteSpace(value))
                {
                    throw new ArgumentException($"Filter value for '{canonicalColumn}' cannot be empty.");
                }

                // Validate value length
                if (value.Length > 500)
                {
                    throw new ArgumentException($"Filter value for '{canonicalColumn}' exceeds maximum length.");
                }

                filters.Add(new FilterCondition
                {
                    Column = canonicalColumn,
                    Operator = operatorName.ToLowerInvariant(),
                    Value = value
                });
            }

            return filters;
        }

        private static (string sortColumn, string sortDirection) ParseSort(
            string sortParam, string sortDirParam, HashSet<string> tableColumns)
        {
            if (string.IsNullOrWhiteSpace(sortParam))
            {
                return ("Id", "ASC");
            }

            string canonicalSort = tableColumns.FirstOrDefault(tc => tc.Equals(sortParam, StringComparison.OrdinalIgnoreCase));
            if (canonicalSort == null)
