                throw new ArgumentException($"Sort column '{SanitizeForLog(sortParam)}' is not allowed for this table.");
            }

            string direction = "ASC";
            if (!string.IsNullOrWhiteSpace(sortDirParam))
            {
                if (!AllowedSortDirections.Contains(sortDirParam))
                {
                    throw new ArgumentException("Sort direction must be 'ASC' or 'DESC'.");
                }
                direction = sortDirParam.ToUpperInvariant();
            }

            return (canonicalSort, direction);
