        private static (string query, List<SqlParameter> parameters) BuildParameterizedQuery(
            string tableName,
            List<string> selectColumns,
            List<FilterCondition> filters,
            string sortColumn,
            string sortDirection,
            int offset,
            int pageSize)
        {
            var parameters = new List<SqlParameter>();

            // Build SELECT clause using validated column names (from allowlist, so safe for identifier use)
            // We bracket-quote identifiers as defense in depth
            string selectClause = string.Join(", ", selectColumns.Select(c => $"[{c}]"));

            // Table name is from allowlist, bracket-quoted for defense in depth
