            {
                queryBuilder.Append(" WHERE ");
                var whereClauses = new List<string>();

                for (int i = 0; i < filters.Count; i++)
                {
                    var filter = filters[i];
                    string paramName = $"@p{i}";
                    string columnRef = $"[{filter.Column}]";

                    switch (filter.Operator)
                    {
                        case "eq":
                            whereClauses.Add($"{columnRef} = {paramName}");
                            parameters.Add(new SqlParameter(paramName, filter.Value));
                            break;

                        case "neq":
                            whereClauses.Add($"{columnRef} <> {paramName}");
                            parameters.Add(new SqlParameter(paramName, filter.Value));
                            break;

                        case "gt":
                            whereClauses.Add($"{columnRef} > {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value, filter.Column));
                            break;

                        case "gte":
                            whereClauses.Add($"{columnRef} >= {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value, filter.Column));
                            break;

                        case "lt":
                            whereClauses.Add($"{columnRef} < {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value, filter.Column));
                            break;

                        case "lte":
                            whereClauses.Add($"{columnRef} <= {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value, filter.Column));
                            break;

                        case "like":
                            // Escape LIKE wildcards in user input, then wrap with %
                            string escapedLikeValue = filter.Value
                                .Replace("[", "[[]")
                                .Replace("%", "[%]")
                                .Replace("_", "[_]");
                            whereClauses.Add($"{columnRef} LIKE {paramName}");
                            parameters.Add(new SqlParameter(paramName, $"%{escapedLikeValue}%"));
                            break;

                        case "in":
                            // Parse comma-separated values into individual parameters
                            var inValues = filter.Value.Split(',', StringSplitOptions.RemoveEmptyEntries)
                                .Select(v => v.Trim())
                                .Where(v => v.Length > 0 && v.Length <= 200)
                                .Take(50) // Limit IN clause items
                                .ToList();

                            if (inValues.Count == 0)
                            {
                                throw new ArgumentException($"IN filter for '{filter.Column}' requires at least one value.");
                            }

                            var inParamNames = new List<string>();
                            for (int j = 0; j < inValues.Count; j++)
                            {
                                string inParamName = $"@p{i}_in{j}";
                                inParamNames.Add(inParamName);
                                parameters.Add(new SqlParameter(inParamName, inValues[j]));
                            }
                            whereClauses.Add($"{columnRef} IN ({string.Join(", ", inParamNames)})");
                            break;

                        default:
                            // Should never reach here due to allowlist validation above
                            throw new ArgumentException($"Unsupported operator: {filter.Operator}");
                    }
                }

                queryBuilder.Append(string.Join(" AND ", whereClauses));
            }

            // ORDER BY using validated column name and direction (both from allowlists)
            queryBuilder.Append($" ORDER BY [{sortColumn}] {sortDirection}");

            // OFFSET/FETCH with parameters
            queryBuilder.Append(" OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY");
            parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = offset });
            parameters.Add(new SqlParameter("@pageSize", SqlDbType.Int) { Value = pageSize });

            return (queryBuilder.ToString(), parameters);
        }

        private static SqlParameter CreateNumericOrDateParameter(string paramName, string value, string columnName)
        {
            // Try parsing as decimal for numeric comparisons
            if (decimal.TryParse(value, System.Globalization.NumberStyles.Any,
                System.Globalization.CultureInfo.InvariantCulture, out decimal numericValue))
            {
                return new SqlParameter(paramName, SqlDbType.Decimal) { Value = numericValue };
            }

            // Try parsing as DateTime
            if (DateTime.TryParse(value, System.Globalization.CultureInfo.InvariantCulture,
                System.Globalization.DateTimeStyles.None, out DateTime dateValue))
            {
                return new SqlParameter(paramName, SqlDbType.DateTime2) { Value = dateValue };
            }

            // Fall back to string comparison
            return new SqlParameter(paramName, value);
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string query, List<SqlParameter> parameters, ILogger log)
        {
            // Connection string from Azure Key Vault reference or App Settings
            // In Azure Functions, use @Microsoft.KeyVault(SecretUri=...) syntax in app settings
            string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            if (string.IsNullOrWhiteSpace(connectionString))
            {
                log.LogError("Database connection string is not configured.");
                throw new InvalidOperationException("Database connection is not configured.");
            }

            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(query, connection))
                {
                    command.CommandType = CommandType.Text;
                    command.CommandTimeout = 30; // 30 second timeout

                    foreach (var param in parameters)
                    {
                        command.Parameters.Add(param);
                    }

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                string fieldName = reader.GetName(i);
                                object value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                                row[fieldName] = value;
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return results;
        }

        /// <summary>
        /// Sanitize a value before including it in log output to prevent log injection.
        /// </summary>
        private static string SanitizeForLog(string input)
        {
            if (string.IsNullOrEmpty(input))
                return "(empty)";

            // Remove newlines and control characters to prevent log injection
            string sanitized = Regex.Replace(input, @"[\r\n\t]", " ");

            // Truncate to reasonable length
            if (sanitized.Length > 100)
            {
                sanitized = sanitized.Substring(0, 100) + "...(truncated)";
            }

            return sanitized;
        }
